import React, { useMemo, useState } from 'react';
import {
  Button,
  Input,
  Modal, dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { DepartmentDto } from '../../../services/master/models';
import { normalizeCode, normalizeCodeOptional } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  CatalogFormFooter,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogTableBusy,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogDocumentHistory,
  CatalogFormHistorySlot,
  CatalogListMasterToolbarSection,
  CatalogListMasterListFooter,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
  proposalEditableFields,
  toProposalFieldDefs,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { masterCatalogDocumentTypes } from '../../../config/documentHistoryClients';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-phong-ban';
const CATALOG_KIND = 'departments';

type FormErrors = Partial<Record<'code' | 'name', string>>;

const PhongBanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<DepartmentDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<DepartmentDto | null>(null);
  const [form, setForm] = useState<Partial<DepartmentDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const proposalFieldDefs = useMemo(
    () => toProposalFieldDefs(proposalEditableFields(schema)),
    [schema],
  );

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useCatalogListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService
        .getDepartments({ search: search.trim() || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: err instanceof Error ? err.message : 'Lỗi tải phòng ban',
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [reloadKey, search, page, pageSize, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã phòng ban';
    if (!form.name?.trim()) next.name = 'Nhập tên phòng ban';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({ isActive: true });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openEdit = (row: DepartmentDto) => {
    setViewOnlyShared(isSharedCatalogReadOnly(row));
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await masterService.updateDepartment(editing.id, {
          name: form.name!.trim(),
          managerEmployeeCode: normalizeCodeOptional(form.managerEmployeeCode),
          isActive: form.isActive ?? true,
        });
      } else {
        await masterService.createDepartment({
          code: normalizeCode(form.code!),
          name: form.name!.trim(),
          managerEmployeeCode: normalizeCodeOptional(form.managerEmployeeCode),
        });
      }
      markClean();
      dispatchAppToast(dispatch, {
        message: editing ? 'Cập nhật phòng ban thành công' : 'Tạo phòng ban thành công',
        type: 'success',
      });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = items.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateDepartment(id, {
          name: row.name,
          managerEmployeeCode: row.managerEmployeeCode,
          isActive: false,
        });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} phòng ban`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteDepartment(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} phòng ban`, type: 'success' });
    }
    refresh();
  };

  const filterBar = (
    <>
      <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
        <Input
          placeholder="Tìm mã, tên..."
          value={searchDraft}
          onChange={e => setSearchDraft(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
        />
      </div>
      <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} hideRefresh />
    </>
  );

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-sitemap" /> Danh mục phòng ban</h1>
        </div>
      </div>

      <CatalogListMasterToolbarSection
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={items}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        proposalFieldDefs={proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined}
      />

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách phòng ban"
        showTableLoading={showTableLoading}
        filters={filterBar}
        footer={
          <CatalogListMasterListFooter
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            shared={shared}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearSelection(); }}
            onPageSizeChange={setPageSize}
          />
        }
      >
        {items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy phòng ban phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={items}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={() => true}
          />
        ) : null}
      </CatalogListShell>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem phòng ban dùng chung' : editing ? 'Sửa phòng ban' : 'Thêm phòng ban'}
        size="md"
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã phòng ban *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing || viewOnlyShared}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên phòng ban *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-managerEmployeeCode`}>
              <label className={styles.label}>Mã trưởng phòng</label>
              <Input
                value={form.managerEmployeeCode ?? ''}
                disabled={viewOnlyShared}
                className={styles.codeInput}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, managerEmployeeCode: normalizeCodeOptional(e.target.value) }));
                }}
              />
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              managerEmployeeCode: form.managerEmployeeCode,
              isActive: form.isActive,
            }}
            {...sharedForm}
          />
          {viewOnlyShared ? (
            <div className={styles.modalActions}>
              <CatalogDocumentHistory
                testIdPrefix={TEST_ID}
                documentType={masterCatalogDocumentTypes.departments}
                documentId={editing?.id}
                documentCode={editing?.code}
              />
              <Button variant="secondary" onClick={closeFormModal}>Đóng</Button>
            </div>
          ) : (
            <CatalogFormFooter
              companyName={editing?.companyName ?? sessionCompanyName}
              testIdPrefix={TEST_ID}
              checked={form.isActive ?? true}
              onActiveChange={c => {
                markDirty();
                setForm(f => ({ ...f, isActive: c }));
              }}
              onCancel={closeFormModal}
              onSave={handleSave}
              saving={saving}
              historySlot={
                <CatalogFormHistorySlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.id, code: editing.code } : null}
                />
              }
              saveDisabled={viewOnlyShared}
            />
          )}
        </div>
      </Modal>

      <CatalogUiSchemaEditorModal
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        isOpen={schemaEditorOpen}
        onClose={() => setSchemaEditorOpen(false)}
        onSaved={() => reloadSchema()}
      />

      <LeaveConfirmModal {...leaveConfirmModalProps} />
    </div>
  );
};

export default PhongBanPage;
